#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

// Read layers.json and scan-result.json
const layersPath = process.argv[2] || '/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/intermediate/layers.json';
const scanResultPath = process.argv[3] || '/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/intermediate/scan-result.json';
const outputPath = process.argv[4] || '/home/cwtrocks/OpenCoreAnalysisKit/.understand-anything/tmp/ua-tour-input.json';

try {
  const layers = JSON.parse(fs.readFileSync(layersPath, 'utf8'));
  const scanResult = JSON.parse(fs.readFileSync(scanResultPath, 'utf8'));

  // Create nodes from layers
  const nodes = [];
  const nodeIdSet = new Set();

  // Add file nodes
  layers.forEach(layer => {
    layer.nodeIds.forEach(nodeId => {
      if (!nodeIdSet.has(nodeId)) {
        nodeIdSet.add(nodeId);

        // Extract file path from nodeId (format: "file:path")
        const filePath = nodeId.replace(/^file:/, '');

        // Find file in scan result
        const fileInfo = scanResult.files?.find(f => f.path === filePath);

        let nodeType = 'file';
        let summary = `File: ${path.basename(filePath)}`;

        // Determine node type based on file extension or path
        if (filePath.endsWith('.md')) {
          nodeType = 'document';
          summary = `Documentation: ${path.basename(filePath)}`;
        } else if (filePath.match(/\.(yml|yaml)$/)) {
          nodeType = 'pipeline';
          summary = `CI/CD pipeline: ${path.basename(filePath)}`;
        } else if (filePath === 'CMakeLists.txt') {
          nodeType = 'config';
          summary = 'CMake build configuration';
        } else if (filePath.match(/\.(sh|bat)$/)) {
          nodeType = 'service';
          summary = `Build script: ${path.basename(filePath)}`;
        } else if (filePath.match(/\.ini$/)) {
          nodeType = 'config';
          summary = `Configuration: ${path.basename(filePath)}`;
        }

        // Add more detailed summary based on file info
        if (fileInfo) {
          summary = `${nodeType === 'file' ? 'Source file' : summary} (${fileInfo.sizeLines} lines, ${fileInfo.language})`;
        }

        nodes.push({
          id: nodeId,
          type: nodeType,
          name: path.basename(filePath),
          filePath: filePath,
          summary: summary
        });
      }
    });
  });

  // Create basic edges based on directory structure and imports
  const edges = [];

  // Simple heuristic: files in same directory or parent-child relationship
  nodes.forEach(node => {
    const dir = path.dirname(node.filePath);

    // Find potential dependencies
    nodes.forEach(targetNode => {
      if (node.id === targetNode.id) return;

      const targetDir = path.dirname(targetNode.filePath);

      // Header-source file relationship
      if (node.filePath.endsWith('.cpp') &&
          targetNode.filePath.endsWith('.h') &&
          node.filePath.replace('.cpp', '.h') === targetNode.filePath) {
        edges.push({
          source: node.id,
          target: targetNode.id,
          type: 'imports'
        });
      }

      // Same directory, likely related
      if (dir === targetDir &&
          node.filePath.endsWith('.cpp') &&
          targetNode.filePath.endsWith('.h')) {
        // Don't add if already added above
        if (!edges.find(e => e.source === node.id && e.target === targetNode.id)) {
          // Check if names match
          const nodeBase = path.basename(node.filePath, '.cpp');
          const targetBase = path.basename(targetNode.filePath, '.h');
          if (nodeBase !== targetBase) {
            edges.push({
              source: node.id,
              target: targetNode.id,
              type: 'imports'
            });
          }
        }
      }
    });
  });

  // Create output structure
  const output = {
    nodes: nodes,
    edges: edges,
    layers: layers.map(l => ({
      id: l.id,
      name: l.name,
      description: l.description
    }))
  };

  fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
  console.log(`Graph data written to ${outputPath}`);
  console.log(`Nodes: ${nodes.length}, Edges: ${edges.length}, Layers: ${layers.length}`);

} catch (error) {
  console.error('Error:', error.message);
  process.exit(1);
}

#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

// Parse command line arguments
const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-tour-analyze.js <input.json> <output.json>');
  process.exit(1);
}

try {
  // Read input data
  const data = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
  const { nodes, edges, layers } = data;

  console.log(`Loaded ${nodes.length} nodes, ${edges.length} edges, ${layers.length} layers`);

  // Build adjacency lists
  const outgoing = new Map(); // node -> [targets]
  const incoming = new Map(); // node -> [sources]

  nodes.forEach(node => {
    outgoing.set(node.id, []);
    incoming.set(node.id, []);
  });

  edges.forEach(edge => {
    if (outgoing.has(edge.source)) {
      outgoing.get(edge.source).push(edge.target);
    }
    if (incoming.has(edge.target)) {
      incoming.get(edge.target).push(edge.source);
    }
  });

  // A. Fan-In Ranking (Importance)
  const fanInRanking = nodes
    .map(node => ({
      id: node.id,
      fanIn: incoming.get(node.id).length,
      name: node.name
    }))
    .sort((a, b) => b.fanIn - a.fanIn)
    .slice(0, 20);

  // B. Fan-Out Ranking (Scope)
  const fanOutRanking = nodes
    .map(node => ({
      id: node.id,
      fanOut: outgoing.get(node.id).length,
      name: node.name
    }))
    .sort((a, b) => b.fanOut - a.fanOut)
    .slice(0, 20);

  // C. Entry Point Candidates
  const entryPointCandidates = [];

  nodes.forEach(node => {
    let score = 0;
    const fileName = path.basename(node.filePath);
    const fileDir = path.dirname(node.filePath);
    const depth = fileDir.split('/').length;

    // Documentation files
    if (node.type === 'document') {
      if (fileName === 'README.md' && depth <= 1) {
        score += 5; // Highest priority for root README
      } else if (fileName.endsWith('.md') && depth <= 1) {
        score += 2;
      }
    }

    // Code entry points
    if (node.type === 'file') {
      const entryFileNames = [
        'index.ts', 'index.js', 'main.ts', 'main.js', 'app.ts', 'app.js',
        'server.ts', 'server.js', 'mod.rs', 'main.go', 'main.py', 'main.rs',
        'manage.py', 'app.py', 'wsgi.py', 'asgi.py', 'run.py', '__main__.py',
        'Application.java', 'Main.java', 'Program.cs', 'config.ru', 'index.php',
        'App.swift', 'Application.kt', 'main.cpp', 'main.c', 'core_parser.cpp'
      ];

      if (entryFileNames.includes(fileName)) {
        score += 3;
      }

      // Root or one level deep
      if (depth <= 2) {
        score += 1;
      }

      // High fan-out (top 10%)
      const fanOut = outgoing.get(node.id).length;
      const top10PercentFanOut = fanOutRanking[Math.floor(fanOutRanking.length * 0.1)]?.fanOut || 0;
      if (fanOut >= top10PercentFanOut) {
        score += 1;
      }

      // Low fan-in (bottom 25%)
      const fanIn = incoming.get(node.id).length;
      const allFanIns = nodes.map(n => incoming.get(n.id).length).sort((a, b) => a - b);
      const bottom25PercentFanIn = allFanIns[Math.floor(allFanIns.length * 0.25)] || 0;
      if (fanIn <= bottom25PercentFanIn) {
        score += 1;
      }
    }

    if (score > 0) {
      entryPointCandidates.push({
        id: node.id,
        score: score,
        name: node.name,
        summary: node.summary,
        type: node.type
      });
    }
  });

  entryPointCandidates.sort((a, b) => b.score - a.score);
  const topEntryPoints = entryPointCandidates.slice(0, 5);

  // D. BFS Traversal from top code entry point
  const topCodeEntry = entryPointCandidates.find(e => e.type === 'file');
  let bfsTraversal = null;

  if (topCodeEntry) {
    const visited = new Set();
    const queue = [{ id: topCodeEntry.id, depth: 0 }];
    const order = [];
    const depthMap = {};
    const byDepth = {};

    visited.add(topCodeEntry.id);

    while (queue.length > 0) {
      const { id, depth } = queue.shift();
      order.push(id);
      depthMap[id] = depth;

      if (!byDepth[depth]) {
        byDepth[depth] = [];
      }
      byDepth[depth].push(id);

      // Follow imports and calls edges
      const targets = outgoing.get(id) || [];
      targets.forEach(targetId => {
        if (!visited.has(targetId)) {
          visited.add(targetId);
          queue.push({ id: targetId, depth: depth + 1 });
        }
      });
    }

    bfsTraversal = {
      startNode: topCodeEntry.id,
      order: order,
      depthMap: depthMap,
      byDepth: byDepth
    };
  }

  // E. Non-Code File Inventory
  const nonCodeFiles = {
    documentation: [],
    infrastructure: [],
    data: [],
    config: []
  };

  nodes.forEach(node => {
    if (node.type === 'document') {
      nonCodeFiles.documentation.push({
        id: node.id,
        name: node.name,
        summary: node.summary
      });
    } else if (node.type === 'service' || node.type === 'pipeline' || node.type === 'resource') {
      nonCodeFiles.infrastructure.push({
        id: node.id,
        name: node.name,
        summary: node.summary
      });
    } else if (node.type === 'table' || node.type === 'schema' || node.type === 'endpoint') {
      nonCodeFiles.data.push({
        id: node.id,
        name: node.name,
        summary: node.summary
      });
    } else if (node.type === 'config') {
      nonCodeFiles.config.push({
        id: node.id,
        name: node.name,
        summary: node.summary
      });
    }
  });

  // F. Tightly Coupled Clusters
  const clusters = [];
  const processed = new Set();

  nodes.forEach(node => {
    if (processed.has(node.id)) return;

    const cluster = new Set([node.id]);
    const candidates = new Set(outgoing.get(node.id));

    // Find bidirectional relationships
    candidates.forEach(targetId => {
      const targetOutgoing = outgoing.get(targetId) || [];
      if (targetOutgoing.includes(node.id)) {
        cluster.add(targetId);
      }
    });

    // Expand cluster
    let expanded = true;
    while (expanded && cluster.size < 5) {
      expanded = false;
      nodes.forEach(candidateNode => {
        if (cluster.has(candidateNode.id)) return;

        let connections = 0;
        cluster.forEach(memberId => {
          if (outgoing.get(candidateNode.id).includes(memberId) ||
              incoming.get(candidateNode.id).includes(memberId)) {
            connections++;
          }
        });

        if (connections >= 2) {
          cluster.add(candidateNode.id);
          expanded = true;
        }
      });
    }

    if (cluster.size >= 2) {
      // Count edges within cluster
      let edgeCount = 0;
      cluster.forEach(id1 => {
        cluster.forEach(id2 => {
          if (id1 !== id2 && outgoing.get(id1).includes(id2)) {
            edgeCount++;
          }
        });
      });

      clusters.push({
        nodes: Array.from(cluster),
        edgeCount: edgeCount
      });

      cluster.forEach(id => processed.add(id));
    }
  });

  clusters.sort((a, b) => b.edgeCount - a.edgeCount);
  const topClusters = clusters.slice(0, 10);

  // G. Layer List
  const layerInfo = {
    count: layers.length,
    list: layers
  };

  // H. Node Summary Index
  const nodeSummaryIndex = {};
  nodes.forEach(node => {
    nodeSummaryIndex[node.id] = {
      name: node.name,
      type: node.type,
      summary: node.summary
    };
  });

  // Create output
  const output = {
    scriptCompleted: true,
    entryPointCandidates: topEntryPoints,
    fanInRanking: fanInRanking,
    fanOutRanking: fanOutRanking,
    bfsTraversal: bfsTraversal,
    nonCodeFiles: nonCodeFiles,
    clusters: topClusters,
    layers: layerInfo,
    nodeSummaryIndex: nodeSummaryIndex,
    totalNodes: nodes.length,
    totalEdges: edges.length
  };

  // Write output
  fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
  console.log(`Analysis complete. Results written to ${outputPath}`);
  console.log(`Entry points found: ${topEntryPoints.length}`);
  console.log(`Top entry point: ${topEntryPoints[0]?.name || 'none'} (score: ${topEntryPoints[0]?.score || 0})`);
  console.log(`BFS traversal: ${bfsTraversal ? 'completed' : 'skipped'}`);
  console.log(`Clusters found: ${topClusters.length}`);

  process.exit(0);

} catch (error) {
  console.error('Error:', error.message);
  console.error(error.stack);
  process.exit(1);
}
